  <svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="20" y="32" fill="#fafafa" font-size="15" font-weight="700" font-family="sans-serif">従来決済 vs DTCCトークン化パイロット</text>
    <g font-family="sans-serif">
      <rect x="250" y="50" width="195" height="26" rx="4" fill="rgba(161,161,170,.18)" stroke="#71717a"/>
      <text x="347" y="68" fill="#d4d4d8" font-size="13" font-weight="700" text-anchor="middle">従来決済 (T+1)</text>
      <rect x="465" y="50" width="215" height="26" rx="4" fill="rgba(56,189,248,.22)" stroke="#38bdf8"/>
